import { Component, OnInit, inject } from '@angular/core';
import { Router } from '@angular/router';
import { AdminCasesService } from '../../../application/services/admin-cases.service';
import { PendingTask } from '../../../application/models/backoffice.models';

@Component({
  selector: 'bo-tasks',
  templateUrl: './tasks.component.html',
  styleUrls: ['./tasks.component.css']
})
export class TasksComponent implements OnInit {
  private readonly adminCasesService = inject(AdminCasesService);
  private readonly router = inject(Router);

  tasks: PendingTask[] = [];
  filter: 'all' | 'urgent' | 'unassigned' = 'all';
  isLoading = true;

  ngOnInit(): void {
    this.loadTasks();
  }

  get filteredTasks(): PendingTask[] {
    if (this.filter === 'urgent') {
      return this.tasks.filter(task => task.priority === 'urgent');
    }
    if (this.filter === 'unassigned') {
      return this.tasks.filter(task => !task.assignedTo);
    }
    return this.tasks;
  }

  loadTasks(): void {
    this.isLoading = true;
    this.adminCasesService.getPendingTasks().subscribe({
      next: tasks => {
        this.tasks = tasks;
        this.isLoading = false;
      },
      error: () => {
        this.tasks = [];
        this.isLoading = false;
      }
    });
  }

  openTask(task: PendingTask): void {
    this.router.navigate(['/cases', task.caseId, 'task', task.id]);
  }

  openCase(task: PendingTask): void {
    this.router.navigate(['/cases', task.caseId]);
  }
}
<div class="space-y-6">
  <div class="bg-white rounded-lg shadow p-6">
    <div class="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
      <div>
        <h3 class="text-lg font-semibold text-gray-900">Bandeja de Tareas</h3>
        <p class="text-sm text-gray-500 mt-1">Trabajo pendiente de revision, subsanacion y resolucion.</p>
      </div>
      <div class="flex gap-2">
        <button type="button" (click)="filter = 'all'" class="px-3 py-2 text-sm rounded-md border" [class.bg-blue-600]="filter === 'all'" [class.text-white]="filter === 'all'">Todas</button>
        <button type="button" (click)="filter = 'urgent'" class="px-3 py-2 text-sm rounded-md border" [class.bg-blue-600]="filter === 'urgent'" [class.text-white]="filter === 'urgent'">Urgentes</button>
        <button type="button" (click)="filter = 'unassigned'" class="px-3 py-2 text-sm rounded-md border" [class.bg-blue-600]="filter === 'unassigned'" [class.text-white]="filter === 'unassigned'">Sin asignar</button>
      </div>
    </div>
  </div>

  <div class="bg-white rounded-lg shadow overflow-hidden">
    <div *ngIf="isLoading" class="p-8 text-center text-gray-500">Cargando tareas...</div>
    <table *ngIf="!isLoading" class="w-full">
      <thead class="bg-gray-50 border-b border-gray-200">
        <tr>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Tarea</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Expediente</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Asignado</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Vencimiento</th>
          <th class="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Prioridad</th>
          <th class="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">Acciones</th>
        </tr>
      </thead>
      <tbody class="divide-y divide-gray-200">
        <tr *ngFor="let task of filteredTasks" class="hover:bg-gray-50">
          <td class="px-6 py-4">
            <div class="font-medium text-gray-900">{{ task.taskName }}</div>
            <div class="text-sm text-gray-500">{{ task.taskType }}</div>
          </td>
          <td class="px-6 py-4 text-sm text-gray-700">{{ task.caseTitle }}</td>
          <td class="px-6 py-4 text-sm text-gray-500">{{ task.assignedTo || 'Sin asignar' }}</td>
          <td class="px-6 py-4 text-sm text-gray-500">{{ task.dueDate ? (task.dueDate | date: 'dd/MM/yyyy') : '-' }}</td>
          <td class="px-6 py-4">
            <span class="px-2 py-1 text-xs font-medium rounded-full" [class.bg-red-100]="task.priority === 'urgent'" [class.text-red-800]="task.priority === 'urgent'" [class.bg-yellow-100]="task.priority === 'normal'" [class.text-yellow-800]="task.priority === 'normal'">
              {{ task.priority === 'urgent' ? 'Urgente' : 'Normal' }}
            </span>
          </td>
          <td class="px-6 py-4 text-right space-x-3">
            <button type="button" (click)="openCase(task)" class="text-gray-600 hover:text-gray-900 text-sm font-medium">Ver expediente</button>
            <button type="button" (click)="openTask(task)" class="text-blue-600 hover:text-blue-800 text-sm font-medium">Resolver</button>
          </td>
        </tr>
        <tr *ngIf="filteredTasks.length === 0">
          <td colspan="6" class="px-6 py-8 text-center text-gray-500">No hay tareas para el filtro seleccionado</td>
        </tr>
      </tbody>
    </table>
  </div>
</div>
